class TestREQ003CartAPI:

    @pytest.mark.positive
    @pytest.mark.api
    def test_TC_REQ_003_01_positive_add_item_to_cart(self, client, auth_headers):
        """
        TC-REQ-003-01 [positive]
        Authenticated user successfully adds item to cart with valid product_id and quantity
        """
        # Arrange
        payload = {"product_id": 5, "quantity": 2}

        # Act
        response = client.post("/cart/items", json=payload, headers=auth_headers)

        # Assert
        assert response.status_code == 201
        data = response.json()
        assert "items" in data
        assert "total_price" in data
        added_item = next((item for item in data["items"] if item["product_id"] == 5), None)
        assert added_item is not None
        assert added_item["quantity"] == 2

    @pytest.mark.positive
    @pytest.mark.api
    def test_TC_REQ_003_02_positive_multiple_items_total(self, client, auth_headers):
        """
        TC-REQ-003-02 [positive]
        Multiple items can be added to cart and total updates correctly
        """
        # Arrange
        items = [
            {"product_id": 5, "quantity": 2},  # $10 each
            {"product_id": 7, "quantity": 1}   # $15 each
        ]

        # Act
        for item in items:
            response = client.post("/cart/items", json=item, headers=auth_headers)
            assert response.status_code == 201

        cart_response = client.get("/cart", headers=auth_headers)

        # Assert
        assert cart_response.status_code == 200
        cart_data = cart_response.json()
        assert len(cart_data["items"]) == 2
        assert cart_data["total_price"] == 35  # (10*2) + (15*1)

