# ── UI Tests ─────────────────────────────────────────
class TestREQ003CartUI:

    @pytest.mark.positive
    @pytest.mark.ui
    def test_TC_REQ_003_05_positive_cart_persistence(self, page):
        """
        TC-REQ-003-05 [positive]
        Cart persists across multiple sessions for same user
        """
        # Arrange - First login and add item
        page.goto(f"{BASE_URL}/login")
        page.wait_for_load_state("networkidle")
        
        page.get_by_label("Email").fill(os.getenv("TEST_USER_EMAIL", "test@example.com"))
        page.get_by_label("Password").fill(os.getenv("TEST_USER_PASSWORD", "testpass123"))
        page.get_by_role("button", name="Login").click()
        page.wait_for_load_state("networkidle")

        # Add item to cart
        page.goto(f"{BASE_URL}/products/5")
        page.wait_for_load_state("networkidle")
        page.get_by_role("spinbutton").fill("2")
        page.get_by_role("button", name="Add to Cart").click()

        # Logout
        page.get_by_role("button", name="Logout").click()
        page.wait_for_load_state("networkidle")

        # Act - Login again and check cart
        page.get_by_label("Email").fill(os.getenv("TEST_USER_EMAIL"))
        page.get_by_label("Password").fill(os.getenv("TEST_USER_PASSWORD"))
        page.get_by_role("button", name="Login").click()
        page.wait_for_load_state("networkidle")

        # Navigate to cart
        page.get_by_role("link", name="Cart").click()
        page.wait_for_load_state("networkidle")

        # Assert
        cart_items = page.locator(".cart-item")
        expect(cart_items).to_have_count(1)
        product_name = page.locator(".cart-item:first-child .product-name")
        expect(product_name).to_be_visible()

        # Cleanup - Remove item from cart
        page.get_by_role("button", name="Remove").click()
        page.wait_for_load_state("networkidle")

